{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a combinatorial optimization problem involving a 9x9 grid and 3x3 stamps. Since the goal is to maximize a sum modulo a large prime, and the number of possible placements is small (7x7 = 49 possible positions for a 3x3 stamp), this can be modeled as a variation of the Maximum Weight Independent Set problem or a coverage problem, but the modulo constraint makes it non-standard. However, the modulo 998244353 is much larger than any possible sum of a 9x9 board (assuming standard integer entries), so the modulo likely only applies to the final sum and does not affect the optimization logic unless the entries are extremely large. I will break this into grid modeling, weight calculation, and optimization.",
  "helpers": [
    {
      "label": "grid_analyzer",
      "instructions": "Given the 9x9 board entries, calculate the total sum of all entries covered by a 3x3 stamp placed at every possible top-left coordinate (i, j) where 0 <= i, j <= 6. Return a list of 49 values representing the weight of each possible stamp placement."
    },
    {
      "label": "optimization_engine",
      "instructions": "Given a list of 49 weights corresponding to 3x3 stamp placements on a 9x9 grid, find a subset of up to 81 placements that maximizes the total sum of the board entries. Note that multiple stamps can overlap, and overlapping cells count their values multiple times (each time they are covered by a stamp). If the problem implies cells can only be counted once, treat this as a Maximum Coverage problem; if cells are counted per stamp, simply pick the top 81 highest-weight stamps. Clarify the overlap rule based on the problem text and solve for the maximum sum."
    }
  ],
  "synthesis_brief": "The parent will take the 49 calculated weights from the grid_analyzer and pass them to the optimization_engine. The optimization_engine will determine the optimal set of stamps. The final answer will be the maximum sum obtained, taken modulo 998244353."
}

